import fs from"fs-promise";import Promise from"bluebird";import path from"path";import home from"user-home";import{biomeFolderName}from"./constants";import{getProjectMetadata}from"./local";export function findVariablesFor(e){console.info(`Sourcing variables for ${e}...`);let o=path.join(biomeFolderName(),`${e}.json`);return fs.readJson(o).then(e=>e.$include?Promise.all(e.$include.map(getEnv)).then(o=>{o=o.map(e=>e[0]);let r=Object.assign.apply(this,o);return delete e.$include,{...e,...r}}):e)}export function getEnv(e){return e?Promise.all([findVariablesFor(e),e]):getProjectMetadata(e).then(e=>(console.info(`Found Biomefile for ${e.name}...`),Promise.all([findVariablesFor(e.name),e.name])))}